text:
{
  "formal_minutes": {
    "meeting_title": "UI Theme Package Release Readiness",
    "project_code": "PUBLIC_MEETING_SMOKE",
    "participants": [
      "Minjun",
      "Seoyeon",
      "Doyun",
      "Hara"
    ],
    "confirmed_decisions": [
      {
        "topic": "공개 릴리스 목표 시점",
        "decision": "스모크 테스트가 통과할 경우 금요일 15:00 KST를 공개 릴리스 목표로 한다."
      },
      {
        "topic": "packageName mismatch 대응 원칙",
        "decision": "packageName mismatch가 발생하면 먼저 package config를 확인하고, 계약 자체가 잘못된 경우에만 스크립트 검토를 진행한다."
      }
    ],
    "rejected_proposals": [
      {
        "proposal": "smoke-theme-pack.mjs에서 packageName mismatch를 무시하도록 변경하자",
        "result": "기각"
      }
    ],
    "internal_stretch_goals": [
      {
        "goal": "수요일 릴리스",
        "status": "내부 스트레치 목표만 해당하며 확정 일정이 아님"
      }
    ],
    "non_decisions": [
      {
        "item": "README 설치 단계는 가능하면 목요일까지 검토 필요",
        "note": "필요성은 언급됐지만 담당자는 지정되지 않음"
      },
      {
        "item": "Hara의 tarball 경로 확인",
        "note": "Minjun의 스모크 결과 공유 이후 진행하기로 했으나 정확한 기한은 정해지지 않음"
      }
    ],
    "risks": [
      {
        "risk": "잘못된 tarball 경로가 릴리스를 지연시킬 수 있음"
      },
      {
        "risk": "README 설치 단계가 오래되었으면 릴리스 노트가 사용자를 오도할 수 있음"
      }
    ],
    "open_questions": [
      {
        "question": "최종 릴리스 승인 권한자는 누구인가?"
      },
      {
        "question": "릴리스 노트에 내부 수요일 스트레치 목표를 언급해야 하는가?"
      }
    ]
  },
  "action_items": [
    {
      "owner": "Minjun",
      "task": "금요일 10:00 KST까지 스모크 테스트를 재실행하고 결과를 공유한다.",
      "due": "금요일 10:00 KST",
      "status": "대기",
      "source_certainty": "확정"
    },
    {
      "owner": "Doyun",
      "task": "금요일 12:00 KST까지 action_items.md에 실패 트리아지 노트를 작성한다.",
      "due": "금요일 12:00 KST",
      "status": "대기",
      "source_certainty": "확정"
    },
    {
      "owner": "Hara",
      "task": "Minjun의 스모크 결과 공유 후 생성된 tarball 경로를 확인한다.",
      "due": "정확한 기한 미정",
      "status": "대기",
      "source_certainty": "확정"
    },
    {
      "owner": null,
      "task": "README 설치 단계를 가능하면 목요일까지 검토한다.",
      "due": "목요일 가능하면",
      "status": "담당자 미정",
      "source_certainty": "언급됨"
    }
  ],
  "followup_note": {
    "what_to_check_next": [
      "Minjun의 스모크 테스트 재실행 결과",
      "스모크 통과 여부에 따른 금요일 15:00 KST 공개 릴리스 진행 가능성",
      "Doyun의 실패 트리아지 노트 작성 여부",
      "Hara의 generated tarball 경로 확인 결과",
      "README 설치 단계의 최신성 및 담당자 지정 필요 여부",
      "최종 릴리스 승인 권한자 확인",
      "릴리스 노트에 내부 수요일 스트레치 목표를 적을지 여부"
    ],
    "what_not_to_invent": [
      "고객명 또는 외부 파트너",
      "예산 정보",
      "보안 사고",
      "프로덕션 장애",
      "법무 승인 요구",
      "미지정 담당자",
      "미정 기한"
    ]
  },
  "non_invention_rules": [
    "인라인 공개 안전 합성 픽스처에 있는 사실만 사용한다.",
    "확정 결정과 기각된 제안, 내부 스트레치 목표, 리스크, 오픈 질문을 혼합하지 않는다.",
    "고객, 예산, 보안, 장애, 법무, 담당자, 기한에 관한 미기재 사실을 추가하지 않는다.",
    "수요일 릴리스는 확정 일정이 아니라 내부 스트레치 목표로만 기록한다.",
    "packageName mismatch 대응은 확정된 원칙대로만 기록하고, 스크립트 수정이 확정된 것처럼 쓰지 않는다."
  ]
}
